const c = $('Connect Singulare Admin').item.json || {};
const data = c.data || c.qrcode || c;
let qr_base64 = data.base64 || '';
// Evolution already returns 'data:image/png;base64,...' prefix sometimes; strip if present
if (qr_base64.startsWith('data:')) {
  qr_base64 = qr_base64.split(',')[1] || qr_base64;
}
const pair_code = data.pairingCode || '';
const qr_string = data.code || '';
const connected = data.state === 'open' || data.state === 'connected';
const html = `<!DOCTYPE html><html lang="pt-BR"><head><meta charset="utf-8"><title>Conectar Singulare admin</title><meta name="viewport" content="width=device-width,initial-scale=1"><meta http-equiv="refresh" content="25"><style>body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;max-width:480px;margin:32px auto;padding:0 16px;color:#18181b;background:#fafaf7}.card{background:#fff;border-radius:16px;padding:24px;box-shadow:0 1px 2px rgba(0,0,0,.04),0 18px 40px -16px rgba(0,0,0,.10)}.pair{font-size:36px;font-weight:700;letter-spacing:6px;font-family:'SF Mono',monospace;background:#f4f4f5;padding:18px 24px;border-radius:12px;text-align:center;margin:8px 0;color:#5746af}.qr{margin:16px 0;text-align:center}.qr img{max-width:280px;border-radius:12px}.small{color:#71717a;font-size:13px;line-height:1.5}h1{font-size:24px;margin:0 0 6px;letter-spacing:-.02em}h3{font-size:15px;margin:28px 0 8px;color:#3f3f46}.tag{display:inline-flex;align-items:center;gap:6px;background:#ecfdf5;color:#047857;padding:4px 10px;border-radius:999px;font-size:11px;font-weight:600;margin-bottom:8px}.ok{background:#ecfdf5;color:#047857;padding:18px;border-radius:12px;text-align:center;font-weight:600}</style></head><body><div class="card"><div class="tag">SINGULARE • CONFIG</div><h1>Conectar canal admin</h1><p class="small">Número: <strong>+55 11 98939-0155</strong> · Instância: <code>singulare-admin</code></p>${connected ? '<div class="ok">✅ Número conectado. Você já pode fechar esta página.</div>' : ''}${!connected && pair_code ? `<h3>Opção A — Código de pareamento (8 chars)</h3><div class="pair">${pair_code}</div><p class="small">No celular do número acima, abra <strong>WhatsApp</strong> → <strong>Aparelhos Conectados</strong> → <strong>Conectar com número de telefone</strong> → digite o código.</p>` : ''}${!connected && qr_base64 ? `<h3>${pair_code ? 'Opção B' : 'Opção A'} — QR Code</h3><div class="qr"><img src="data:image/png;base64,${qr_base64}" alt="QR Code"></div><p class="small">No celular Singulare, abra <strong>WhatsApp</strong> → <strong>Aparelhos Conectados</strong> → <strong>Conectar um aparelho</strong> → escaneie o QR acima.</p>` : ''}${!connected && !pair_code && !qr_base64 ? '<p class="small" style="color:#dc2626">Não foi possível gerar QR/pair agora. Recarregue a página em 10s.</p>' : ''}<hr style="border:none;border-top:1px solid #e4e4e7;margin:24px 0"><p class="small">${connected ? 'Conectado em ' + new Date().toLocaleString('pt-BR') : 'Os códigos expiram em ~25s. Esta página recarrega sozinha.'}</p></div></body></html>`;
return [{ json: { html, pair_code, qr_string, has_qr: !!qr_base64, connected } }];

